// El asunto llega así:
// "galaktiturkos camisas 3.pdf enviado correctamente a sublimarte.alqueria@gmail.com"
// Extraemos todo lo que está ANTES de la primera palabra clave

const asunto = $input.first().json.subject || '';

// Quitamos el nombre del archivo (.pdf, .cdr, etc.) y lo que sigue
const match = asunto.match(/^(.+?)(?:\s+\S+\.(?:pdf|cdr|ai|eps|jpg|png|zip))/);
let equipo = match ? match[1].trim() : asunto.split(' enviado')[0].trim();

// Limpieza básica: quitar números al final (ej: "galaktiturkos camisas 3" → "galaktiturkos")
// Solo dejamos la primera parte antes de un espacio + tipo de prenda conocido
const prendas = ['camisas','camiseta','pantalon','pantaloneta','uniforme','conjunto','portero','buso','chaqueta'];
for (const prenda of prendas) {
  const idx = equipo.toLowerCase().indexOf(' ' + prenda);
  if (idx !== -1) { equipo = equipo.substring(0, idx).trim(); break; }
}

return [{ json: { equipo, asuntoOriginal: asunto } }];

